INSERT INTO public.photos VALUES (22054, 'Parque Primo de Rivera aâ”śâ–’os 50', 'Paseo de San Sebastiâ”śĂ­n; Parque Grande. .', 1950, 1950, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63585700, -0.89607100, '0101000020E6100000C79BFC169DACECBF62F71DC363D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14911691472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14911691472.webp', 'https://www.flickr.com/photos/zaragozaantigua/14911691472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22057, 'La Casa Grande 1955', 'En 1955 fue inaugurada la Residencia Sanitaria Josâ”śÂ® Antonio, "la Casa Grande", en el arbolado y despejado paseo de Isabel la Catâ”śâ”‚lica cerca del Colegio-Residencia de Nuestra Seâ”śâ–’ora del Pilar para Huâ”śÂ®rfanos e Hijos del Magisterio, cuyo edificio figura al fondo a la derecha. Fuente visual: www.bancodeimagenesmedicina.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919054055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919054055.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919054055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22101, 'Prolongaciâ”śâ”‚n Fernando el Catâ”śâ”‚lico 1955', 'Vista del entorno de la Feria de Muestras, la "Residencia Sanitaria Josâ”śÂ® Antonio", y la entrada al Parque Primo de Rivera por el Puente del Trece de Septiembre. La imagen (utilizada para Postal de la Editorial Sicilia) ha sido capturada desde la torre de la Editorial Luis Vives. Un tranvâ”śÂˇa de la Lâ”śÂˇnea 11 "Parque" esta dando la vuelta en la plaza Emperador Carlos para tomar rumbo a Plaza de Espaâ”śâ–’a. A la derecha, tras la Feria, estâ”śĂ­n comenzando las obras para la construcciâ”śâ”‚n de un nuevo estadio de fâ”śâ•‘tbol. Tras los campos de herbâ”śĂ­ceas, el nuevo Convento de Jerusalâ”śÂ®n. Al fondo, detrâ”śĂ­s de la Carretera de los Enlaces, pabellones del antiguo Cuartel de Casablanca. Fuente visual: en www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63756000, -0.89812100, '0101000020E6100000E2395B4068BDECBF6F9EEA909BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20472937299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20472937299.webp', 'https://www.flickr.com/photos/zaragozaantigua/20472937299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22113, 'La &quot;Casa Grande&quot; c.1950', 'Imagen de la Residencia Sanitaria "Josâ”śÂ® Antonio" en pleno proceso de construcciâ”śâ”‚n. Diseâ”śâ–’ada por Fernando Garcâ”śÂˇa Mercadal, las obras comenzaron en 1948, siendo terminadas en 1952. La inauguraciâ”śâ”‚n oficial fue en 1955. La imagen ha sido capturada desde las traseras del enorme edificio, junto a la calle Gonzalo Calamita, con el râ”śÂˇo Huerva a la derecha. Fuente visual: www.cehopu.cedex.es/', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.63494800, -0.90007300, '0101000020E6100000496760E465CDECBF8F54DFF945D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22288467369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22288467369.webp', 'https://www.flickr.com/photos/zaragozaantigua/22288467369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22154, 'Editorial Luis Vives 1958', 'Imagen publicitaria de la Editorial Luis Vives, comercializadora de los libros Edelvives. La empresa se ubicâ”śâ”‚ entre 1941 y 1975 en el paseo de Fernando el Catâ”śâ”‚lico 63. A la izquierda, la calle de Luis Vives. Fuente visual: www.flickr.com/photos/114031783@N02/', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63830700, -0.89691300, '0101000020E6100000936E4BE482B3ECBF68E7340BB4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29368652992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29368652992.webp', 'https://www.flickr.com/photos/zaragozaantigua/29368652992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22161, 'Feria de Muestras 1958', 'En 1958, Zaragoza soportâ”śâ”‚ un amplio despliegue conmemorativo de los sitios que habâ”śÂˇan tenido lugar 150 aâ”śâ–’os antes. Se trasladâ”śâ”‚ el cadâ”śĂ­ver de Palafox desde Madrid a la cripta del Pilar. La Instituciâ”śâ”‚n Fernando el Catâ”śâ”‚lico celebrâ”śâ”‚ un congreso de historia en el que la tâ”śâ”‚nica general fue comparar la Guerra Civil con la de la Independencia, atribuyendo a ambas el carâ”śĂ­cter de cruzada catâ”śâ”‚lica. Hubo dos exposiciones, en la Aljaferâ”śÂˇa sobre los Sitios y en el Museo Etnolâ”śâ”‚gico del parque Primo de Rivera sobre etnografâ”śÂˇa aragonesa y del sur de Francia. Y en el recinto de la Feria de Muestras, se celebrâ”śâ”‚ una Exposiciâ”śâ”‚n Hispano Francesa, conmemorativa de la celebrada en 1908, inaugurâ”śĂ­ndose el Pabellâ”śâ”‚n Francâ”śÂ®s y dando por concluida la construcciâ”śâ”‚n del recinto. La medalla conmemorativa de este â”śâ•‘ltimo evento reproduce las instalaciones de la Feria de Muestras en el paseo de Isabel la Catâ”śâ”‚lica, asâ”śÂˇ como los sâ”śÂˇmbolos vigentes de los dos paâ”śÂˇses, y el nuevo pabellâ”śâ”‚n al fondo a la derecha. Fuente visual: www.ebay.es', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63746900, -0.89934600, '0101000020E6100000B43A394371C7ECBF5F9B8D9598D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30608389495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30608389495.webp', 'https://www.flickr.com/photos/zaragozaantigua/30608389495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22183, 'Cuartel Palafox 1959', 'Imagen capturada como souvenir en el patio de armas del cuartel de Palafox, sede del Regimiento de Montaâ”śâ–’a nâ”¬â•‘ 20. Al fondo, la puerta principal de ingreso, recayente a la calle Domingo Miral. Fuente visual: www.flickr.com/photos/ejercitodetierra/12831102125/in/alb...', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63974300, -0.90029700, '0101000020E61000002FFB75A73BCFECBF276C3F19E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31952620822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31952620822.webp', 'https://www.flickr.com/photos/zaragozaantigua/31952620822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22211, 'RS Josâ”śÂ® Antonio 1955', 'Imagen capturada en la amplia zona a la izquierda de la prolongaciâ”śâ”‚n de la Gran Vâ”śÂˇa, junto al cauce del râ”śÂˇo Huerva, donde habâ”śÂˇa sido construida la gran residencia del Instituto Nacional de Previsiâ”śâ”‚n, que con proyecto de Fernando Garcâ”śÂˇa Mercadal fue inaugurada oficialmente como Residencia Sanitaria Josâ”śÂ® Antonio. En sus 16 plantas de altura albergaba capacidad para un mâ”śĂ­ximo de 596 camas, e incluâ”śÂˇa ambulatorio, quirâ”śâ”‚fanos, maternidad, solarium, sala de conferencias y capilla. La fotografâ”śÂˇa se centra en el original ingreso principal a la residencia, con rampas laterales para vehâ”śÂˇculos y escaleras centrales para peatones, ascendentes desde el nivel de la calle entre jardines y â”śĂ­rboles. Una ampliaciâ”śâ”‚n acometida a principios de los aâ”śâ–’os setenta, que elevâ”śâ”‚ la capacidad de la residencia hasta las 1400 camas, transformâ”śâ”‚ completamente este ingreso. Fuente visual: bancodeimagenesmedicina.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63541400, -0.90057700, '0101000020E61000000EF450DB86D1ECBFD4B5F63E55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44635378341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44635378341.webp', 'https://www.flickr.com/photos/zaragozaantigua/44635378341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22234, 'La Romareda 1958', 'Vista aâ”śÂ®rea centrada en la Residencia Sanitaria Josâ”śÂ® Antonio, la prolongaciâ”śâ”‚n de la avenida de Fernando el Catâ”śâ”‚lico y el novâ”śÂˇsimo estadio municipal de La Romareda, flanqueado a la izquierda por el nuevo convento de Jerusalâ”śÂ®n, y a la derecha por el ampliado recinto de la Feria Nacional de Muestras. Tras la carretera de Valencia, tradicional entorno agrâ”śÂˇcola con campos de cultivo surtidos de torres y regados por la acequia de La Romareda. A la derecha, el cuartel de Palafox.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63558800, -0.90064200, '0101000020E6100000D5EDEC2B0FD2ECBF72DD94F25AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50226827921.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50226827921.webp', 'https://www.flickr.com/photos/zaragozaantigua/50226827921/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22237, 'La Residencia Sanitaria 1955', 'Imagen de la reciâ”śÂ®n terminada Residencia Sanitaria Josâ”śÂ® Antonio, cuyas obras comenzaron en 1947 en la prolongaciâ”śâ”‚n de Fernando el Catâ”śâ”‚lico, principio del actual de Isabel la Catâ”śâ”‚lica. Se muestra en todo su luminoso volumen el escalonado diseâ”śâ–’o que desde los pâ”śâ”‚rticos de acceso va ascendiendo en altura hasta las plantas superiores del hospital, desde donde las vistas de la ciudad son espectaculares. En primer tâ”śÂ®rmino, campos de herbâ”śĂ­ceas donde un par de aâ”śâ–’os despuâ”śÂ®s se inaugurarâ”śÂˇa el estadio municipal de La Romareda.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63546700, -0.90052400, '0101000020E6100000596B28B517D1ECBFF7578FFB56D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50855883151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50855883151.webp', 'https://www.flickr.com/photos/zaragozaantigua/50855883151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22302, 'Antonio Machâ”śÂˇn 1965', 'Firma de autâ”śâ”‚grafos a enfermeras de la Residencia Sanitaria Josâ”śÂ® Antonio (Casa Grande), por parte de Antonio Machâ”śÂˇn (1903-1977), câ”śÂ®lebre cantante cubano afincado en Espaâ”śâ–’a, que en la â”śÂ®poca de la visita concertada al hospital zaragozano pasaba por una racha de declive de popularidad. Fuente: www.facebook.com/photo.php?fbid=642369309205738&set=p...', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15598106018.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15598106018.webp', 'https://www.flickr.com/photos/zaragozaantigua/15598106018/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22448, 'Vista Parque Primo de Rivera 1960', 'Vista aâ”śÂ®rea sobre el parque Primo de Rivera. Destacan las torres de la Feria de Muestras y de la Editorial Luis Vives. Fuente: TAF Helicâ”śâ–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63552000, -0.89725400, '0101000020E6100000DE9046054EB6ECBF1AFA27B858D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31208759382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31208759382.webp', 'https://www.flickr.com/photos/zaragozaantigua/31208759382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22449, 'Vista &quot;Casa Grande&quot; 1960', 'Vista aâ”śÂ®rea centrada en la Residencia Sanitaria Josâ”śÂ® Antonio o "Casa Grande", con el estadio de fâ”śâ•‘tbol de la Romareda a la izquierda, junto a la Feria de Muestras. Fuente: TAF Helicâ”śâ–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63521200, -0.89996000, '0101000020E61000003FA9F6E978CCECBF6D0377A04ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31208862682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31208862682.webp', 'https://www.flickr.com/photos/zaragozaantigua/31208862682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25598, 'A la Romareda 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 01/10/1973. Un lunes de fâ”śâ•‘tbol era cosa extraordinaria, fuera de lo normal, si es que ese adjetivo encaja en el universo balompâ”śÂ®dico. Y bien calentito estaba todavâ”śÂˇa el 4 a 0 endosado por el Madrâ”śÂˇ, un par de dâ”śÂˇas antes, en la quinta jornada de Liga. Ademâ”śĂ­s, este era un partido amistoso (homenaje a Garcâ”śÂˇa Carnicer), y el natural competitivo decae, por mucho que el "rival" fuera la "Selecciâ”śâ”‚n Aragonesa", si bien la pugna Zaragoza-Aragâ”śâ”‚n es hecho bien trascendente en esta ciudad, quasiantropolâ”śâ”‚gico, que supera la mera autofagia. Por aquellos aâ”śâ–’os se hablaba mucho de eso, incluso desde un punto de vista extradeportivo. La imagen captura el estado de los accesos al recinto de la Romareda desde Isabel la Catâ”śâ”‚lica, que mâ”śĂ­s que accesos, asemejan traviesa gymkana, cuando no demencial "pista americana". El concepto "barrera arquitectâ”śâ”‚nica", o "accesibilidad", eran aâ”śâ•‘n meros delirios foranos. Pero nada parecâ”śÂˇa importar para ver al equipo del momento, jugara contra quien jugara, lo que se jugara, y aunque hubiera que sortear montaâ”śâ–’as de grava y conglomerados: Nieves, Violeta, Garcâ”śÂˇa Castany, Planas, Ocampos, Diarte... y con Arrâ”śâ•‘a a punto de llegar, lo merecâ”śÂˇan. Vale. Al fondo, a la izquierda, la mole de los bloques denominados "Marvel", entre Fray Luis Amigo y Alfonso X el Sabio. Debajo, la esquina neomudâ”śÂ®jar de Luis Bermejo cuando toda esa manzana, junto con la Câ”śĂ­mara de Comercio, conformaba el Recinto Ferial. La masa vegetal es el Parque Grande; por abajo fluye el Huerva. A la derecha, arranque del nuevo edificio del Centro Materno-Infantil de la Casa Grande, lugar aâ”śâ•‘n muy frecuentado en aquellos aâ”śâ–’os.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63671000, -0.90009500, '0101000020E61000003D61890794CDECBFA18499B67FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14873091373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14873091373.webp', 'https://www.flickr.com/photos/zaragozaantigua/14873091373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25609, 'Romareda 1957', 'Vista aâ”śÂ®rea de las construcciones que poco a poco iban jalonando el nuevo paseo de Isabel la Catâ”śâ”‚lica: el cuartel de Palafox, el recinto de la feria de Muestras, la "Residencia Sanitaria Jose Antonio", el estadio municipal de "La Romareda", el Monasterio de Santa Marâ”śÂˇa de Jerusalâ”śÂ®n de las HH. Clarisas, y el Colegio-residencia Nâ”¬Â¬. Sâ”¬Â¬. del Pilar para Huerfanos e Hijos del Magisterio. Junto a la "Casa Grande", el râ”śÂˇo Huerva y el Parque Primo de Rivera. Son tambiâ”śÂ®n visibles los productivos campos de cultivo de esta zona de la lejana periferia zaragozana. Fuente visual: Servicio Aragonâ”śÂ®s de Salud (Pâ”śâ•‘blica) sectorzaragozados.salud.aragon.es/', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63614900, -0.90093200, '0101000020E6100000976F7D586FD4ECBF0A3197546DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18996959306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18996959306.webp', 'https://www.flickr.com/photos/zaragozaantigua/18996959306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25620, 'Don Cicuta 1973', 'Nacido en el arranque del siglo XX (1901), Valentâ”śÂˇn Tornos Lâ”śâ”‚pez fue un veterano actor teatral, cinematogrâ”śĂ­fico y televisivo de discreta notoriedad popular, pues los suyos eran esos papeles secundarios siempre fuera del foco mediâ”śĂ­tico, a desmano de lo protagâ”śâ”‚nico. Asâ”śÂˇ fue hasta que aceptâ”śâ”‚ encarnar a un carpetovetâ”śâ”‚nico personaje, de nombre "Don Cicuta", en un concurso televisivo que tenâ”śÂˇa una calabaza como referencia, y que comenzâ”śâ”‚ a ser emitido en 1972. Su sentida interpretaciâ”śâ”‚n de los eternos valores patrios, en unos pocos programas se tradujo en uno de esos contundentes, râ”śĂ­pidos y populares "fenâ”śâ”‚menos sociolâ”śâ”‚gicos" carentes de lâ”śâ”‚gica y explicaciâ”śâ”‚n racional alguna. Valentâ”śÂˇn, caracterizado como el personaje televisivo Don Cicuta, fue convertido en un objeto icâ”śâ”‚nico de consumo masivo (juguetes de todo tipo, cromos, hasta un vinilo), y de merecido reconocimiento profesional ("TP" de Oro de 1972 al "Personaje mâ”śĂ­s Popular"). En este estado de las cosas, fue invitado a la Feria Internacional de Maquinaria Agrâ”śÂˇcola (FIMA) de 1973, como popularâ”śÂˇsimo personaje que era, para hacer publicidad de Motor Ibâ”śÂ®rica S.A. En la imagen, azafatas de la empresa y pâ”śâ•‘blico de la Feria en general, rodean a Valentâ”śÂˇn Tornos/Don Cicuta en proceso de firmar un autâ”śâ”‚grafo. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63759000, -0.89959300, '0101000020E6100000A5BC564277C9ECBFDA20938C9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23891803424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23891803424.webp', 'https://www.flickr.com/photos/zaragozaantigua/23891803424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25630, 'P.â”¬â•‘ de Isabel la Catâ”śâ”‚lica 1955', 'Vista del entorno de la Feria de Muestras, la reciente Residencia Sanitaria Josâ”śÂ® Antonio, y la entrada al Parque Primo de Rivera por el Puente del Trece de Septiembre. La imagen ha sido capturada desde la torre de la Editorial Luis Vives. Un tranvâ”śÂˇa de la lâ”śÂˇnea 11 "Parque" permanece en la terminal de la plaza Emperador Carlos V, antes de tomar rumbo a la plaza de Espaâ”śâ–’a, y una unidad de la lâ”śÂˇnea 15 "Casablanca" se aproxima por Isabel la Catâ”śâ”‚lica, encaminada hacia esa misma direcciâ”śâ”‚n. Esta imagen tiene mucho en comâ”śâ•‘n con otra similar comercializada por ediciones SICILIA (tambiâ”śÂ®n incluida en este Gran Archivo Zaragoza Antigua), tal vez tomadas ambas por la misma persona. Fuente visual: postal de Ediciones DARVI, en www.abebooks.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63751000, -0.89841300, '0101000020E6100000D3A3A99ECCBFECBFBD6F7CED99D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34043226291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34043226291.webp', 'https://www.flickr.com/photos/zaragozaantigua/34043226291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25640, 'Vista c.1956', 'Imagen capturada desde la notable altura de la terraza mâ”śĂ­s norteâ”śâ–’a de la moderna "Residencia Sanitaria Josâ”śÂ® Antonio del Seguro Obligatorio de Enfermedad" y orientada en la direcciâ”śâ”‚n del paseo de Fernando el Catâ”śâ”‚lico, que hacia el fondo muestra el fondo de las antiguas torres y câ”śâ•‘pulas del centro de la ciudad. A la izquierda, la torre-mirador de la Feria de Muestras.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63539500, -0.89954800, '0101000020E6100000A6D425E318C9ECBF5E85949F54D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51676817060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51676817060.webp', 'https://www.flickr.com/photos/zaragozaantigua/51676817060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22654, 'Ciudad Universitaria 1976', 'Postal. Aspecto de la Ciudad Universitaria o Campus San Francisco de Zaragoza, en 1976. En primer plano, estanque desaparecido. Tras la Facultad de Ciencias (1950), el Hospital Clâ”śÂˇnico Universitario (1974). Fuente: www.facebook.com/photo.php?fbid=513848895438611&set=g...', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64172000, -0.89829400, '0101000020E6100000412D060FD3BEECBF359886E123D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21397902242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21397902242.webp', 'https://www.flickr.com/photos/zaragozaantigua/21397902242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25642, 'Cines Renoir 2012', 'Los multicines Renoir de Zaragoza estaban en el centro comercial Los Porches del Audiorama, con entrada por la calle de Luis Bermejo 4. Se inauguraron con un pase de la pelâ”śÂˇcula "Niâ”śâ–’o nadie", de Josâ”śÂ® Luis Borau, el 22 de enero de 1997 y abrieron sus puertas a todo el pâ”śâ•‘blico una semana despuâ”śÂ®s. Fueron cerrados el 10 de mayo de 2012, y un tiempo despuâ”śÂ®s sustituidos por un gimnasio.', 2012, 2012, 2012, 'Siglo XXI', 'UNIVERSIDAD', 41.63691200, -0.89964800, '0101000020E6100000882D3D9AEAC9ECBF0937195586D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54391001010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54391001010.webp', 'https://www.flickr.com/photos/zaragozaantigua/54391001010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22636, 'La Milagrosa 1970', 'En el aâ”śâ–’o de 1907 la Duquesa de Villahermosa creâ”śâ”‚ una fundaciâ”śâ”‚n para niâ”śâ–’os/as (menores de 14 aâ”śâ–’os) pobres de Zaragoza, a cuyo cargo estarâ”śÂˇan las Hijas de La Caridad de San Vicente de Paâ”śâ•‘l. El 12 de febrero de 1916, en la finca del solar Maestro Estremiana 3-5, se realizan obras de acomodaciâ”śâ”‚n para impartir allâ”śÂˇ educaciâ”śâ”‚n, pero el edificio se remodela con vigas de madera verde, lo cual traerâ”śĂ­ luego serias consecuencias. El 2 de octubre de 1921 Sor Concepciâ”śâ”‚n Marâ”śÂˇn Segura recibe en herencia la casa de verano de sus padres, situada en el "barrio de Torrero" (el chaflâ”śĂ­n del paseo Cuellar nâ”¬â•‘ 57 con la Vâ”śÂˇa de San Fernando nâ”¬â•‘ 1), con la finalidad de dar enseâ”śâ–’anza gratuita a las niâ”śâ–’as del barrio. En etapas sucesivas se van adquiriendo nuevos terrenos en los que se crearâ”śĂ­n "Las Escuelas de La Milagrosa". Con el tiempo, estas "Escuelas de La Milagrosa" llegaron a tener un nâ”śâ•‘mero de alumnas muy elevado, lo que hizo imposible continuar en esa ubicaciâ”śâ”‚n. Justo en ese momento, la Fundaciâ”śâ”‚n Duquesa Villahermosa no podâ”śÂˇa continuar su labor educativa en la casa de Maestro Estremiana, ya que se encontraba muy deteriorada: las vigas de madera verde, antes citadas, cedieron al secarse y la termita causâ”śâ”‚ graves destrozos en la estructura de la casa. A estos hechos se uniâ”śâ”‚ un incendio en los desvanes que obligâ”śâ”‚ a desalojar definitivamente el edificio. Tras la venta del edificio de Cuâ”śÂ®llar de "Las Escuelas de La Milagrosa", se comienza la construcciâ”śâ”‚n de un nuevo colegio en el solar de la calle del Maestro Estremiana 3 y 5 (anterior Fundaciâ”śâ”‚n Duquesa Villahermosa), con el nombre de "Colegio La Milagrosa", inaugurado el 19 de marzo de 1978. En la imagen, captura del chaflâ”śĂ­n de "Las Escuelas de La Milagrosa", entre el paseo de Cuâ”śÂ®llar 57 (con vehâ”śÂˇculos aparcados en la acera), y la Vâ”śÂˇa de San Fernando 1 (hacia la derecha, donde seâ”śâ–’ala el cartel a "Alcaâ”śâ–’iz"). En la actualidad todo esto forma parte del gran bloque de viviendas del 55-57 del paseo de Cuâ”śÂ®llar.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63543500, -0.88449500, '0101000020E610000076374F75C84DECBFECDD1FEF55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20246682241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20246682241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20246682241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22679, '&quot;Bosque de la Amistad&quot; 1970', 'El Bosque de la Amistad estaba a los pies del Cabezo de Buenavista, en el parque de Primo de Rivera, y se utilizaba como escenario del concurso de belleza Maja Internacional organizado por la Asociaciâ”śâ”‚n Goya Internacional que se celebraba, como era tradicional desde 1966, en el Palacio de la Lonja, dentro de las Fiestas de Primavera. En la imagen, las candidatas a la quinta ediciâ”śâ”‚n de este certamen posan vestidas con atavâ”śÂˇos tradicionales.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63464100, -0.89330400, '0101000020E6100000FB592C45F295ECBFB2D991EA3BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26304711951.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26304711951.webp', 'https://www.flickr.com/photos/zaragozaantigua/26304711951/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22703, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1971', 'Imagen capturada en el paseo de Ruiseâ”śâ–’ores y centrada en el murete que delimitaba el acceso al antiguo Colegio Pompiliano en el nâ”¬â•‘ 26, antaâ”śâ–’o seâ”śâ–’alada por su notable altura que destacaba en las fotografâ”śÂˇas de la zona, ya derribado y en trâ”śĂ­nsito de conversiâ”śâ”‚n en una parcela con varios modernos y selectos inmuebles. A su izquierda, el moderno colegio Pompiliano. Al fondo, bloques del Grupo Salduba todavâ”śÂˇa recayentes al cauce al aire de la acequia de las Adulas, o de San Josâ”śÂ®. A la izquierda, fuera de plano, perduraban las antiguas viviendas unifamiliares de los nâ”śâ•‘meros 24 y 22 (esta ya esquinera con la calle de Fernando de Antequera), si bien tiempo despuâ”śÂ®s tambiâ”śÂ®n fueron sustituidas por modernas construcciones residenciales de alta categorâ”śÂˇa. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.63627900, -0.88923600, '0101000020E61000009DA04D0E9F74ECBFD8101C9771D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27546737448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27546737448.webp', 'https://www.flickr.com/photos/zaragozaantigua/27546737448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22823, 'Parque de Primo de Rivera 1970', 'Simpâ”śĂ­tica imagen capturada durante la ceremonia de plantaciâ”śâ”‚n de arbustos en el "Bosque de la Amistad" (final del paseo de San Sebastiâ”śĂ­n en el parque de Primo de Rivera) inserta en el programa de actividades de la elecciâ”śâ”‚n de la "Maja Internacional". La de la fotografâ”śÂˇa era la representante austrâ”śÂˇaca, seâ”śâ–’orita Inge Krottendorfer, que "ataviada con el traje tâ”śÂˇpico de su paâ”śÂˇs" posa para los reporteros grâ”śĂ­ficos con una pala mientras dos operarios de Parques y Jardines realizan la tarea.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63415200, -0.89400100, '0101000020E6100000E6EB32FCA79BECBFB4588AE42BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51720247037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51720247037.webp', 'https://www.flickr.com/photos/zaragozaantigua/51720247037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23001, 'Parque Primo de Rivera aâ”śâ–’os 90', 'Escaleras de acceso al Cabezo de Buena Vista, con la estatua de Alfonso I el Batallador al fondo. Fuente: Foto para postal de Comercial Josan. Cesiâ”śâ”‚n de la familia de Josâ”śÂ® Marâ”śÂˇa Sanz Gonzâ”śĂ­lez a Rafael Castillejo. Dataciâ”śâ”‚n y procesado:', 1990, 1990, 1999, 'Anos 90', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27146138930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27146138930.webp', 'https://www.flickr.com/photos/zaragozaantigua/27146138930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23021, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1990', 'Granulada y parcial imagen, pero muy interesante, de la que fuera antigua fâ”śĂ­brica de harinas "La Imperial de Aragâ”śâ”‚n", en funcionamiento desde mediados de los aâ”śâ–’os sesenta del siglo XIX hasta los aâ”śâ–’os ochenta del pasado siglo XX en su domicilio social del paseo de Ruiseâ”śâ–’ores nâ”¬â•‘ 40. La captura se habrâ”śÂˇa realizado desde la vecina urbanizaciâ”śâ”‚n de inmuebles adosados que la rodea por sus lados norte y oeste, durante el proceso de derribo de esta fâ”śĂ­brica para dar paso a una moderna urbanizaciâ”śâ”‚n de 24 inmuebles de selecta alta gama. En primer plano, â”śĂ­rboles que jalonaban el original acceso a la harinera desde el paseo de Ruiseâ”śâ–’ores. A la izquierda, balaustrada que delimitaba su perâ”śÂˇmetro, en este caso recayente al referido paseo. A la derecha, patio que vertebraba las instalaciones fabriles con edificios de una, dos y tres alturas. En el centro de la imagen, decorativa fachada principal de la fâ”śĂ­brica recayente tambiâ”śÂ®n al paseo del Canal, resultado de la remodelaciâ”śâ”‚n diseâ”śâ–’ada por el arquitecto Miguel â”śĂĽngel Navarro hacia 1920. Al fondo, â”śĂ­rboles de la ribera del Canal Imperial y modernos edificios de las calles de Joaquâ”śÂˇn Octavio de Toledo y del Cabezo de Buenavista Fuente visual: AMZ.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63413000, -0.89098500, '0101000020E6100000FB3F87F9F282ECBFCCB4FD2B2BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43590730681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43590730681.webp', 'https://www.flickr.com/photos/zaragozaantigua/43590730681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23454, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1990', 'Una de las caracterâ”śÂˇsticas de las calles privadas de la ciudad, fueran de los ensanches obreros o burgueses, como en este caso, es que no perdura documentaciâ”śâ”‚n municipal respecto a su edificaciâ”śâ”‚n, ya que fue a partir de 1913 cuando se hizo obligatorio el trâ”śĂ­mite de solicitud de licencia para edificar en ellas, y durante unos cuantos aâ”śâ–’os este requisito fue bastante "flexible" en su aplicaciâ”śâ”‚n. Este edificio fue concebido como vivienda unifamiliar, con la denominaciâ”śâ”‚n "Villa Rosita", propiedad de Raimundo Balet, proyectada por Manuel Isasi Isasmendi y edificada en 1903 en el nâ”¬â•‘ 13 (actual nâ”¬â•‘ 39) del paseo de los Ruiseâ”śâ–’ores. Posteriormente ha sufrido numerosas reformas, algunas muy sustanciales, como la de 1919 a cargo de Miguel â”śĂĽngel Navarro Pâ”śÂ®rez, o la que le aâ”śâ–’adiâ”śâ”‚ el esquinado torreâ”śâ”‚n modernista de la imagen, rematado con câ”śâ•‘pula recubierta con vistosos trozos cerâ”śĂ­micos. En el momento de capturar la imagen, cuando ya apenas si quedaban rastros de su traza original, aâ”śâ•‘n contaba con el letrero de su mâ”śĂ­s reciente funciâ”śâ”‚n: sede desde 1960 del colegio Santo Tomâ”śĂ­s de Aquino de bachillerato masculino primero, luego Mixto de BUP y COU hasta su cierre en 1986. Fuente visual: "Zaragoza barrio a barrio"', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63651000, -0.88907700, '0101000020E61000007D06D49B5173ECBFDAC9E02879D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15328438123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15328438123.webp', 'https://www.flickr.com/photos/zaragozaantigua/15328438123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21490, 'Director de la AGM 1928', 'AHPZ. Estudio Coyne. 1928. "Francisco Franco, en la Academia General Militar." La primera Academia General Militar (Toledo) fue disuelta en 1892. En 1927, durante la Dictadura de Primo de Rivera, el golpista general propuso al rey reabrirla. Asâ”śÂˇ se hizo, y la A.G.M. (Segunda â”śĂ«poca) se enclavâ”śâ”‚ en Zaragoza, por su situaciâ”śâ”‚n estratâ”śÂ®gica y por la proximidad del campo de maniobras de S. Gregorio. Para ello, se invirtieron ingentes cantidades de dinero pâ”śâ•‘blico, y se levantâ”śâ”‚ un enorme complejo en estilo neomudâ”śÂ®jar. Como primer director del nuevo centro, Primo de Rivera eligiâ”śâ”‚ a un prometedor joven general, procedente del tercio â”¬Â˝africanistaâ”¬â•— del ejâ”śÂ®rcito, Francisco Franco Bahamonde, que desempeâ”śâ–’â”śâ”‚ el cargo desde agosto de 1927 al 14 de julio de 1931, cuando la reforma militar llevada a cabo por el gobierno de la Segunda Repâ”śâ•‘blica democrâ”śĂ­tica espaâ”śâ–’ola, volviâ”śâ”‚ al sistema de las Academias Especiales de las Armas. Esta reforma intentâ”śâ”‚ una soluciâ”śâ”‚n al sinsentido de la realidad organizativa del ejâ”śÂ®rcito espaâ”śâ–’ol, con 21.000 jefes y oficiales (entre ellos, 800 generales) para 118.000 soldados de tropa. Pocos aâ”śâ–’os despuâ”śÂ®s se llevâ”śâ”‚ a cabo otra "reforma" (golpe de estado fracasado que desembocâ”śâ”‚ en guerra), radical, dolorosa y sangrienta, que definiâ”śâ”‚ no sâ”śâ”‚lo el futuro del ejâ”śÂ®rcito, sino el de todo el paâ”śÂˇs. En ambos casos estuvo por el medio el fotografiado. En la imagen, el general Francisco Franco en su despacho posa en su despacho del cuartel del Carmen, donde provisionalmente estaban instaladas las oficinas de la academia.', 1928, 1928, 1928, 'Anos 20', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15202789213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15202789213.webp', 'https://www.flickr.com/photos/zaragozaantigua/15202789213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21497, 'Monasterio de Santa Fe de Huerva c.1920', 'Imagen exterior del antiguo Monasterio de Santa Fe de Huerva, en la parte mâ”śĂ­s al Sur de la ciudad. Cisterciense en fâ”śĂ­brica barroca del s. XVIII, estâ”śĂ­ abandonado desde la exclaustraciâ”śâ”‚n de 1835, y tuvo que ser objeto de una intervenciâ”śâ”‚n pâ”śâ•‘blica de urgencia en 1981 para evitar su total ruina, ante la inacciâ”śâ”‚n de sus privados propietarios. En la imagen, visual del antiguo monasterio en los comienzos del S. XX, en la zona de su acceso principal. A la izquierda, a apenas 140 metros, el cauce del râ”śÂˇo Huerva. Por donde circula el ciclista seguido de chiquillerâ”śÂˇa, hoy hay un aparcamiento y un establecimiento hostelero, en la confluencia de la calle Camino del Plano, y la Avenida de la Muralla de Santa Fe.', 1920, 1920, 1920, 'Anos 20', NULL, 41.57758700, -0.94988800, '0101000020E6100000739CDB847B65EEBF21CCED5EEEC94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15348604094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15348604094.webp', 'https://www.flickr.com/photos/zaragozaantigua/15348604094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21583, 'San Juan de Mozarrifar 1923', 'El martes 10 de julio de 1923, Zaragoza y sus inmediaciones fueron testigos de una rara acumulaciâ”śâ”‚n catastrâ”śâ”‚fica. De madrugada se produjo un terremoto, haciendo sonar las campanas de las iglesias. Al inicio de la tarde, las nubes oscurecieron la ciudad y un ciclâ”śâ”‚n la agitâ”śâ”‚ con fuerza, derribando chimeneas como la de la fâ”śĂ­brica de galletas Patria. Una granizada de considerables dimensiones asolâ”śâ”‚ las calles. Las tormentas continuaron hasta el crepâ”śâ•‘sculo. Se cortaron las vâ”śÂˇas fâ”śÂ®rreas. En Villanueva de Gâ”śĂ­llego se sufrieron graves inundaciones. Y en San Juan de Mozarrifar se hundieron 33 casas, siendo los vecinos evacuados en barcas, momento que recoge la foto. Al fondo, la papelera de Las Navas, y sus chimeneas.', 1923, 1923, 1923, 'Anos 20', NULL, 41.71404800, -0.83737100, '0101000020E610000057CD7344BECBEABF19E3C3EC65DB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24546633600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24546633600.webp', 'https://www.flickr.com/photos/zaragozaantigua/24546633600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21708, 'AGM 1938', '"Frente de Aragâ”śâ”‚n. Prisioneros republicanos y de las Brigadas Internacionales capturados en el avance nacional sobre Lâ”śÂ®rida". 8 de mayo de 1938. Desde julio de 1936, los sublevados contra la Repâ”śâ•‘blica habâ”śÂˇan habilitado un campo de concentraciâ”śâ”‚n en el Cuartel de infanterâ”śÂˇa de San Gregorio. Conforme avanzaban las operaciones militares victoriosas para los fascistas, especialmente tras la Batalla de Teruel y la del Segre (Lâ”śÂ®rida), el volumen de prisioneros "rojos" desbordâ”śâ”‚ la capacidad de este campo. Tras la Batalla del Ebro, la tendencia se agravarâ”śÂˇa. Es por ello que la cercana fâ”śĂ­brica papelera de "Las Navas", en San Juan de Mozarrifar, serâ”śÂˇa habilitada como Campo de Concentraciâ”śâ”‚n principal en la zona, hasta mâ”śĂ­s allâ”śĂ­ de la guerra (1943). En la imagen, Prisioneros de guerra republicanos "posando" en el Patio de Armas de la Academia General Militar, donde eran exhibidos para las câ”śĂ­maras de la propaganda, antes de enviarlos al campo de concentraciâ”śâ”‚n. Especialmente buscados por los objetivos eran los voluntarios internacionalistas capturados. Y si eran negros, bingo. Fuente visual: Archivo Josâ”śÂ® F. Demarâ”śÂˇa Campâ”śâ•‘a. Foto: Josâ”śÂ® Demarâ”śÂˇa Vâ”śĂ­zquez "Campâ”śâ•‘a".', 1938, 1938, 1938, 'Anos 30', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17070203990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17070203990.webp', 'https://www.flickr.com/photos/zaragozaantigua/17070203990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21743, 'AGM 1935', 'Con la llegada de la reformista Segunda Repâ”śâ•‘blica, hubo tambiâ”śÂ®n mudanzas para el gremio militar desde el Ministerio de la Guerra. Asâ”śÂˇ, en junio de 1931 se decreta el cierre de la Academia General Militar de Zaragoza, por motivos econâ”śâ”‚micos, ideolâ”śâ”‚gicos, y polâ”śÂˇticos. Desde ese momento, la reivindicaciâ”śâ”‚n de la AGM se convirtiâ”śâ”‚ en una de las seâ”śâ–’as de identidad de las derechas. La imagen se corresponde con uno de los reportajes publicados al objeto de denunciar el estado ruinoso de los edificios que, aunque fueron inaugurados en 1927, "antes de tres meses" estarâ”śÂˇan hundidos si no se ponâ”śÂˇa remedio. Tras el golpe de Estado del 18 de julio de 1936, como las instalaciones seguâ”śÂˇan sorprendentemente en pie, fueron reconvertidas para servir de temporal campo de concentraciâ”śâ”‚n durante unos aâ”śâ–’os. En 1940, el enorme complejo fue reinaugurado oficialmente como AGM, y sometido a sucesivas ampliaciones. En la imagen, aâ”śÂ®rea vista del conjunto de edificios de la AGM, poco antes del supuesto hundimiento, no producido. Fuente: Foto Marâ”śÂˇn Chivite, "Crâ”śâ”‚nica" (Madrid).', 1935, 1935, 1935, 'Anos 30', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21835033640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21835033640.webp', 'https://www.flickr.com/photos/zaragozaantigua/21835033640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21802, 'Aerâ”śâ”‚dromo Sanjurjo 1938', 'Imagen identificada en el aerâ”śâ”‚dromo Sanjurjo de Zaragoza, posiblemente relacionada con el escâ”śÂ®nico ceremonial de despedida a la tripulaciâ”śâ”‚n de un Dornier Do-17 E-1 de la Legiâ”śâ”‚n Câ”śâ”‚ndor caâ”śÂˇdo en combate contra las Fuerzas Aâ”śÂ®reas de la Repâ”śâ•‘blica Espaâ”śâ–’ola. Al fondo, un par de los modernâ”śÂˇsimos bombarderos ligeros Do-17 E-1 que los alemanes denominaban "Fliegender Bleistift" (lâ”śĂ­piz volador) por su alargado fuselaje, y que los espaâ”śâ–’oles redenominaron mâ”śĂ­s castizamente "Bacalao".', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26451566078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26451566078.webp', 'https://www.flickr.com/photos/zaragozaantigua/26451566078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21832, 'AGM 1937', 'Imagen con el posado de destacados oficiales del Corpo di Truppe Volontarie (CTV) formado por tropas regulares del ejâ”śÂ®rcito italiano, y camisas negras o milicianos del Partido Fascista italiano, enviado por Mussolini a Espaâ”śâ–’a en respaldo de los alzados en armas contra la Repâ”śâ•‘blica democrâ”śĂ­tica. Entre los oficiales, posiblemente se encuentra el general Mario Roatta "Mancini", cuarto de la segunda fila, nombrado por Mussolini jefe de las tropas italianas en Espaâ”śâ–’a en 1936, hasta su relevo tras la derrota en la batalla de Guadalajara (marzo de 1937) por el general Ettore Bastico (a su derecha), que tambiâ”śÂ®n serâ”śĂ­ relevado en octubre de ese aâ”śâ–’o (esta vez tras solicitud expresa de Franco), por el general Mario Berti, el sâ”śÂ®ptimo de la misma fila, hasta su relevo en octubre de 1938 por el general Gastone Gambara. El grupo de oficiales posa delante del pabellâ”śâ”‚n principal que flanquea el ingreso al gran patio central de la AGM (a la izquierda, fuera de plano). Fuente visual: Foto Elâ”śÂ®ctrica (Zaragoza), en www.todocoleccion.net/', 1937, 1937, 1937, 'Anos 30', NULL, 41.69976200, -0.87091200, '0101000020E6100000DB34B6D782DEEBBFE57D1CCD91D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33365947334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33365947334.webp', 'https://www.flickr.com/photos/zaragozaantigua/33365947334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21850, 'Garrapinillos 1935', 'Imagen capturada durante la inauguraciâ”śâ”‚n oficial del reclamado puente de paso sobre el Canal Imperial que conectara directamente el barrio de Garrapinillos con su tâ”śÂ®rmino agrâ”śÂˇcola, al otro lado del Canal. Este paso se ubicâ”śâ”‚ inmediato a la almenara de La Sagrada y el camino de Bâ”śĂ­rboles, a la izquierda. A la ceremonia acudiâ”śâ”‚ notable representaciâ”śâ”‚n institucional del Ayuntamiento, la DPZ, la Junta del Canal, alcaldes de barrios rurales y juntas de sindicatos de riegos. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', NULL, 41.67502600, -1.03376700, '0101000020E6100000CCF10A444F8AF0BF90F9804067D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35707605974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35707605974.webp', 'https://www.flickr.com/photos/zaragozaantigua/35707605974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21887, 'Aerâ”śâ”‚dromo Sanjurjo 1939', 'Singular y luminosa imagen correspondiente a la celebraciâ”śâ”‚n en el Aerâ”śâ”‚dromo Sanjurjo del "Dâ”śÂˇa de la Luftwaffe" el 1 de marzo de ese aâ”śâ–’o, aniversario cuatro de la fundaciâ”śâ”‚n del "Arma Aâ”śÂ®rea" de la Alemania nazi. En primer tâ”śÂ®rmino, autoridades militares espaâ”śâ–’olas, italianas y alemanas saludan a la imponente parada militar compuesta, al fondo, por las tripulaciones y aeronaves de la Legiâ”śâ”‚n Câ”śâ”‚ndor estacionadas en este importante aerâ”śâ”‚dromo, entre las que se distinguen cazas Messerschmitt Bf 109-E y bombarderos Heinkel He 111-E/3. De telâ”śâ”‚n de fondo natural, la sierra de Alcubierre.', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49667569022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49667569022.webp', 'https://www.flickr.com/photos/zaragozaantigua/49667569022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21910, 'Aerâ”śâ”‚dromo Sanjurjo 1938', 'Entraâ”śâ–’able estampa guerracivilista compuesta a base de bombas de aviaciâ”śâ”‚n, con el inconfundible tono marcial de la Legiâ”śâ”‚n Câ”śâ”‚ndor, para desear a todo el mundo una "Feliz" fiesta del lunes de "Pentecostâ”śÂ®s" desde la base aâ”śÂ®rea de utilizaciâ”śâ”‚n conjunta italo-germano-espaâ”śâ–’ola de Zaragoza. Esta tradicional fiesta cristiana en Alemania celebra el "descenso del Espâ”śÂˇritu Santo", de forma que la presencia de las bombas en la foto bien podrâ”śÂˇa considerarse una "broma" macabra, aunque es probable que los destinatarios de las mismas las recibieran con mâ”śĂ­s terror que broma.', 1938, 1938, 1938, 'Anos 30', NULL, 41.67695000, -1.06696100, '0101000020E610000024B891B24512F1BF7B832F4CA6D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51854911646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51854911646.webp', 'https://www.flickr.com/photos/zaragozaantigua/51854911646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21957, 'Esclusas de Valdegurriana 1949', 'Las antiguas "inclusas de Val de Gurriana" (por estar en la val, o barranco, de ese nombre) formaban parte de la inmensa obra civil del Canal Imperial acometida a finales del siglo XVIII con el propâ”śâ”‚sito de proveer de agua suficiente a Zaragoza, y de permitir la navegaciâ”śâ”‚n Cantâ”śĂ­brico-Mediterrâ”śĂ­neo. En este caso, cuatro kilâ”śâ”‚metros aguas abajo de la "Playa de Torrero", y para salvar los 13 metros de acentuado desnivel, sobre un terreno de muy mala calidad, se construyeron cuatro esclusas en piedra sillar maravillosamente tallada, y unas compuertas de paso. Junto a la primera esclusa se levantâ”śâ”‚ la "Casa de Compuertas", o Almenara de San Bernardo, para regular el Contra-Canal y un riego de inmediatos campos de cultivo. Pero esta descomunal obra fue estâ”śÂ®ril en su propâ”śâ”‚sito principal, pues la porosidad del terreno calcâ”śĂ­reo, y las simas, hicieron del todo imposible continuar la obra tal y como estaba diseâ”śâ–’ada. Las siguientes esclusas construidas, las de Torrecilla de Valmadrid, tres kilâ”śâ”‚metros aguas abajo, quedaron asâ”śÂˇ varadas entre la estepa, sin ver pasar gota de agua. Luego fueron depredadas de sillares, y maltratadas por la desidia, el abandono. En la imagen, aspecto de la enormidad de la voluntad polâ”śÂˇtica y dineros pâ”śâ•‘blicos que fueron necesarios para levantar las esclusas de Valdegurriana. Toda una joya de la demediada Ilustraciâ”śâ”‚n en Zaragoza, y jalâ”śâ”‚n inexcusable para paseantes del Canal Imperial. Fuente visual: fotografâ”śÂˇa de Mariano Lacruz Berdejo, amablemente aportada por Mariano Lacruz Pâ”śÂ®rez (Archivo Familia Lacruz Pâ”śÂ®rez).', 1949, 1949, 1949, 'Anos 40', NULL, 41.61116500, -0.85628000, '0101000020E610000011018750A566EBBFDCBA9BA73ACE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20039981196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20039981196.webp', 'https://www.flickr.com/photos/zaragozaantigua/20039981196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21997, 'Peâ”śâ–’aflor c.1949', 'Imagen de la calle del Paso del barrio de Peâ”śâ–’aflor de Gâ”śĂ­llego, con buena vista de la mudâ”śÂ®jar torre e iglesia parroquial de Nâ”¬Â¬ Sâ”¬Â¬ del Coro de los â”śĂĽngeles, en cuyo lateral figura la correspondiente placa de la memoria histâ”śâ”‚rica en recuerdo de los muertos por Dios y la Espaâ”śâ–’a nacionalista entre 1936 y 1939. Las parcelas de la imagen, hasta la plaza del Rosario, perduran remozadas, y algunas algo recrecidas. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1949, 1949, 1949, 'Anos 40', NULL, 41.76056400, -0.79822000, '0101000020E61000007B6B60AB048BE9BFEA4141295AE14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32600703694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32600703694.webp', 'https://www.flickr.com/photos/zaragozaantigua/32600703694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22147, 'Polâ”śÂˇgono de La Cartuja 1956', 'Dibujo del proyecto ganador en el concurso nacional para la creaciâ”śâ”‚n de un polâ”śÂˇgono industrial junto a La Cartuja Baja. El emplazamiento fue elegido por disponer de agua (râ”śÂˇo Ebro y Canal Imperial), carretera y ferrocarril. "Los vientos dominantes alejarâ”śĂ­n de Zaragoza los humos de las factorâ”śÂˇas y las aguas residuales irâ”śĂ­n al Ebro". Se preveâ”śÂˇa que fuera la zona industrial mâ”śĂ­s grande de Espaâ”śâ–’a, con una poblaciâ”śâ”‚n total de 60 000 habitantes. En ese entorno se inaugurâ”śâ”‚ en 2006 el polâ”śÂˇgono Empresarium, algo mâ”śĂ­s modesto. Fuente visual: revista Aragâ”śâ”‚n, SIPA (1956).', 1956, 1956, 1956, 'Anos 50', NULL, 41.60294700, -0.81740800, '0101000020E6100000FDA36FD23428EABF541C075E2DCD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26595028749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26595028749.webp', 'https://www.flickr.com/photos/zaragozaantigua/26595028749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22186, 'Camino de San Antonio c.1955', 'Imagen de la "escuela de primera enseâ”śâ–’anza en Miraflores", sita en el camino de San Antonio, que desde la almenara de San Antonio del Canal Imperial descendâ”śÂˇa en paralelo al escorredero de la Media Legua, cruzaba el camino de Enmedio, y llegaba hasta la carretera de Castellâ”śâ”‚n. Esta ubicaciâ”śâ”‚n estaba flanqueada por dos lâ”śÂˇneas ferroviarias: a la izquierda, fuera de plano, la lâ”śÂˇnea Madrid-Barcelona; a la derecha, la lâ”śÂˇnea del ferrocarril a Utrillas, con la seâ”śâ–’al del paso a nivel de la caseta "Escorredero". El escorredero de la Media Legua fluye por detrâ”śĂ­s del edificio. Esta escuela tenâ”śÂˇa su parte para niâ”śâ–’os, y su parte para niâ”śâ–’as, y entre ambas, la capilla. Tras unas pocas dâ”śÂ®cadas de servicio, el edifico perdiâ”śâ”‚ su funciâ”śâ”‚n, y la propiedad recayâ”śâ”‚ en la archidiâ”śâ”‚cesis de Zaragoza, que en 2002 se la vendiâ”śâ”‚ a la Hermandad del Refugio, que la ampliâ”śâ”‚ y convirtiâ”śâ”‚ en la Casa de San Josâ”śÂ®, para acogida de jâ”śâ”‚venes inmigrantes tutelados, entre 2006-2009. Fuente visual: foto Jarke, en www.todocoleccion.net/', 1955, 1955, 1955, 'Anos 50', NULL, 41.62288700, -0.85323000, '0101000020E610000021EA3E00A94DEBBF410DDFC2BACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32030296225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32030296225.webp', 'https://www.flickr.com/photos/zaragozaantigua/32030296225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22196, 'Estaciâ”śâ”‚n Aula Dei c.1950', 'Obras de construcciâ”śâ”‚n de la Estaciâ”śâ”‚n Experimental de Aula Dei, segâ”śâ•‘n proyecto de Teodoro Râ”śÂˇos Balaguer de 1946. Serâ”śĂ­ inaugurada en 1952, con una sola ala de las dos previstas. Fuente: Historia de la Estaciâ”śâ”‚n Experimental de Aula Dei, 2014.', 1950, 1950, 1950, 'Anos 50', NULL, 41.72462200, -0.81198400, '0101000020E61000002A029CDEC5FBE9BF26FBE769C0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33283269562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33283269562.webp', 'https://www.flickr.com/photos/zaragozaantigua/33283269562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22232, 'Coso Medio 1955', 'Imagen capturada en el tramo medio del Coso durante las fiestas del Cincuentenario de la Coronaciâ”śâ”‚n canâ”śâ”‚nica de Nuestra Seâ”śâ–’ora del Pilar (1905), celebradas entre los dâ”śÂˇas 15 y 22 de mayo de 1955. La escena se centra en el paso de la imagen de la Virgen de Nuestra Seâ”śâ–’ora de Arcos de la localidad bajoaragonesa de Albalate del Arzobispo, participante en la procesiâ”śâ”‚n celebrada el dâ”śÂˇa 20 de mayo con treinta regionalistas Vâ”śÂˇrgenes acompaâ”śâ–’adas de las correspondientes autoridades locales, grupos de devotos y devotas venidos desde esos municipios, asâ”śÂˇ como grupos folklâ”śâ”‚ricos varios (en este caso, de dance), rondallas, bandas de mâ”śâ•‘sica, cornetas y tambores. Ese mismo dâ”śÂˇa, pero en sesiâ”śâ”‚n matinal, el rector magnâ”śÂˇfico Juan Cabrera y Felipe consagrâ”śâ”‚ la Universidad de Zaragoza al Inmaculado Corazâ”śâ”‚n de Marâ”śÂˇa, aâ”śâ–’adiâ”śÂ®ndole de esta forma una excelencia acadâ”śÂ®mica extracurricular, sobrenatural y fantâ”śĂ­stica. A la izquierda, la calle de Eusebio Blasco y la chaflanera esquina del Teatro Principal, sede del selecto I Congreso Nacional de Teatro Catâ”śâ”‚lico, con ponencias y disertaciones acadâ”śÂ®micas, amâ”śÂ®n de varias representaciones escâ”śÂ®nicas del ramo. A la derecha, un "Topolino" en servicio en la tranviaria lâ”śÂˇnea 13. San Josâ”śÂ®, aguarda pacientemente en el Coso el desarrollo de la procesiâ”śâ”‚n para poder llegar a su terminal en las traseras del Teatro Principal. La magnificencia de estas celebraciones, acompaâ”śâ–’adas de un apacible clima primaveral, fueron el germen del posterior establecimiento de unas anuales Fiestas de Primavera que, siempre vinculadas a la fecha gloriosa de la Coronaciâ”śâ”‚n de la Virgen el 20 de mayo, incluyeron algunos festejos profanos o laicos susceptibles de convertir a Zaragoza en un atractivo destino turâ”śÂˇstico mundial.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65171900, -0.87937800, '0101000020E6100000E84CDA54DD23ECBF469737876BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50050073122.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50050073122.webp', 'https://www.flickr.com/photos/zaragozaantigua/50050073122/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22269, 'Base aâ”śÂ®rea c.1965', 'Base aâ”śÂ®rea de Zaragoza. Fue utilizada por la Fuerza Aâ”śÂ®rea de los Estados Unidos (USAF) desde 1954 hasta 1992, siendo una de las 3 bases aâ”śÂ®reas de la USAF en Espaâ”śâ–’a durante la Guerra Frâ”śÂˇa, junto a la de Torrejâ”śâ”‚n y a la de Morâ”śâ”‚n. La presencia de militares yanquis en Zaragoza supuso una vâ”śÂˇa de entrada del rock en el paâ”śÂˇs. El uso estadounidense del recinto fue contestado por las organizaciones locales de izquierda, organizando marchas anuales hasta su supuesto abandono por parte de USAF.', 1965, 1965, 1965, 'Anos 60', NULL, 41.67288600, -1.06027500, '0101000020E61000002D431CEBE2F6F0BFD7F7E12021D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864970256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864970256.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864970256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22339, 'Calle Mâ”śĂ­rtires 1968', 'Foto Josâ”śÂ® Antonio Duce, 1968. Calle de los Mâ”śĂ­rtires en el Tubo de Zaragoza, con la plaza de Espaâ”śâ–’a a espaldas del fotâ”śâ”‚grafo. Fuente: www.gozazaragoza.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65250300, -0.88048400, '0101000020E610000028D714C8EC2CECBF5DC5E23785D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20068713651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20068713651.webp', 'https://www.flickr.com/photos/zaragozaantigua/20068713651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22453, 'Base Aâ”śÂ®rea 1962', 'Imagen de un aviâ”śâ”‚n de transporte Douglas C-54C "Skymaster" del Mando Estratâ”śÂ®gico de la USAF, estacionado en una pista de la Base Aâ”śÂ®rea de Zaragoza. Este modelo fue el primer aviâ”śâ”‚n de transporte presidencial de la repâ”śâ•‘blica norteamericana (previo al "Air Force One"). En la identificativa torre de control aeroportuaria, visual del oximorâ”śâ”‚nico lema de las instalaciones. Fuente visual: www.usarmygermany.com', 1962, 1962, 1962, 'Anos 60', NULL, 41.67786400, -1.06798100, '0101000020E610000072FDBB3E7316F1BF60915F3FC4D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31605982403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31605982403.webp', 'https://www.flickr.com/photos/zaragozaantigua/31605982403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22490, 'Paseo de la Independencia 1964', 'Vista aâ”śÂ®rea del paseo de la Independencia, con el Pilar al fondo. Fuente: Foto TAF. Revista Triunfo.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65162000, -0.88165200, '0101000020E6100000E97E4E417E36ECBFB3B5BE4868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46302992465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46302992465.webp', 'https://www.flickr.com/photos/zaragozaantigua/46302992465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22494, 'Cartuja de Aula Dei 1968', 'Imagen capturada un soleado dâ”śÂˇa de invierno en la ajardinada plaza de ingreso a la cartuja de Aula Dei, flanqueada por el edificio de la procura (a la izquierda, fuera de plano), y por el de la hospederâ”śÂˇa (a la derecha, fuera de plano). Al fondo, la monumental y barroca portada que da acceso a la iglesia. En primer tâ”śÂ®rmino, un hermano lego de la contemplativa Orden fundada por San Bruno, afanado en un trabajo manual entre la hora nona y las vâ”śÂˇsperas de la Santâ”śÂˇsima Virgen.', 1968, 1968, 1968, 'Anos 60', NULL, 41.73256300, -0.81273000, '0101000020E61000006E4C4F58E201EABF3CA1D79FC4DD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48213983731.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48213983731.webp', 'https://www.flickr.com/photos/zaragozaantigua/48213983731/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22667, 'Aeropuerto 1971', 'Jardines ante el edificio terminal de pasajeros del aeropuerto de Zaragoza, al fondo, junto a la torre de control y comunicaciones, a la izquierda de la imagen, conjunto diseâ”śâ–’ado por el arquitecto Josâ”śÂ® de Yarza y Garcâ”śÂˇa. Este campo de aviaciâ”śâ”‚n, situado en el barrio rural de Garrapinillos, en la margen derecha del Canal Imperial de Aragâ”śâ”‚n, fue resultado de la puesta a disposiciâ”śâ”‚n para uso civil del aerâ”śâ”‚dromo Sanjurjo, decidida en 1946 e inaugurada en 1950. En primer tâ”śÂ®rmino, Monumento a la Aeronâ”śĂ­utica, realizado por los alumnos del Centro Politâ”śÂ®cnico Virgen del Pilar como trabajo prâ”śĂ­ctico, en hierro forjado y acero inoxidable. Tras la gran remodelaciâ”śâ”‚n del aeropuerto entre 2006 y 2008, la escultura se halla en paradero incierto, aunque las construcciones preexistentes han sido conservadas. En el lugar de los jardines se extiende un aparcamiento en superficie.', 1971, 1971, 1971, 'Anos 70', NULL, 41.66267300, -1.00702700, '0101000020E61000001C06F357C81CF0BF9A780778D2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22867497374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22867497374.webp', 'https://www.flickr.com/photos/zaragozaantigua/22867497374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
